import{_ as o,r as t,o as a,c,a as e,b as s,F as i,d as r,e as l}from"./app.6e60246e.js";const p={},u=e("h2",{id:"javascript\u5F02\u6B65\u6A21\u5F0F\u5FEB\u901F\u6307\u5357",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#javascript\u5F02\u6B65\u6A21\u5F0F\u5FEB\u901F\u6307\u5357","aria-hidden":"true"},"#"),r(" javascript\u5F02\u6B65\u6A21\u5F0F\u5FEB\u901F\u6307\u5357")],-1),d=r("\u539F\u6587\uFF1A"),m={href:"https://www.imaginarycloud.com/blog/asynch-javascript-patterns-guide/",target:"_blank",rel:"noopener noreferrer"},f=r("JAVASCRIPT ASYNC PATTERNS QUICK GUIDE"),y=r(" \u4F5C\u8005\uFF1AJoel Reis \u539F\u6280\u672F\u535A\u6587\u7531 Joel Reis \u64B0\u5199\u53D1\u5E03 \u8BD1\u8005\uFF1Agoogle\u7FFB\u8BD1 \u6574\u7406\uFF1ABoswell"),h=l(`<p>\u4ECEWeb\u5E94\u7528\u7A0B\u5E8F\u5230\u670D\u52A1\u5668\u548C\u79FB\u52A8\u5E94\u7528\u7A0B\u5E8F\uFF0C\u4ECE\u5C0F\u578B\u7A0B\u5E8F\u5230\u5927\u578B\u9879\u76EE\uFF0CJavaScript\u65E0\u5904\u4E0D\u5728\u3002\u8FD9\u662F\u63A5\u53D7\u4EFB\u4F55\u9879\u76EE\u7684\u4E3B\u8981\u9009\u62E9\uFF0C\u56E0\u4E3A\u5B83\u662F2018\u5E74\uFF0CJS\u662F\u4E00\u79CD\u66F4\u6210\u719F\u7684\u8BED\u8A00\uFF0C\u6709\u4E00\u4E2A\u5E9E\u5927\u7684\u793E\u533A\u652F\u6301\u5B83\u3002</p><p>\u5728JavaScript\u4E2D\uFF0C\u6240\u6709\u4EE3\u7801\u5728\u4E8B\u4EF6\u5FAA\u73AF\u4E0A\u540C\u6B65\u8FD0\u884C\uFF0C\u4E8B\u4EF6\u5FAA\u73AF\u6309\u987A\u5E8F\u6267\u884C\u7A0B\u5E8F\u7684\u5C0F\u5757\u3002\u5728\u4E8B\u4EF6\u5FAA\u73AF\u4E2D\uFF0C\u6BCF\u6B21\u8FED\u4EE3\u79F0\u4E3A\u201Ctick\u201D\u5E76\u8FD0\u884C\u76F4\u5230\u961F\u5217\u4E3A\u7A7A\u3002\u6BCF\u4E2A\u5757\u90FD\u6709\u4E00\u4E2A\u201Ctick\u201D\u8FDB\u884C\u5904\u7406\uFF0C\u5728\u5B8C\u6210\u540E\uFF0C\u4E0B\u4E00\u4E2A\u5757\u5F00\u59CB\u3002\u5BF9\u4E8E\u5C0F\u578B\u5E94\u7528\u7A0B\u5E8F\uFF0C\u8FD9\u5DF2\u7ECF\u8DB3\u591F\u4E86\uFF0C\u4F46\u662F\u5F53\u6211\u4EEC\u5F00\u59CB\u6267\u884C\u9700\u8981\u66F4\u591A\u65F6\u95F4\u7684\u66F4\u91CD\u8981\u64CD\u4F5C\u65F6\uFF0C\u4F8B\u5982\u8BBF\u95EE\u6570\u636E\u5E93\u6216\u901A\u8FC7Internet\u83B7\u53D6\u6570\u636E\uFF0C\u6211\u4EEC\u9700\u8981\u66F4\u597D\u7684\u673A\u5236\u6765\u5904\u7406\u5B83\u4EEC\u3002</p><p>\u591A\u5E74\u6765\uFF0CJS\u751F\u6001\u7CFB\u7EDF\u4E2D\u51FA\u73B0\u4E86\u6A21\u5F0F\u548C\u5E93\u6765\u5904\u7406\u5F02\u6B65\u7F16\u7A0B\uFF0C\u4F8B\u5982\u56DE\u8C03\uFF0C\u627F\u8BFA\uFF0C\u751F\u6210\u5668\uFF0C\u5F02\u6B65/\u7B49\u5F85\uFF0CWeb\u5DE5\u4F5C\u8005\u548CNPM\u6CE8\u518C\u8868\u4E0A\u7684\u5305\uFF0C\u5982async\uFF0Cbluebird\uFF0Cco\u6216RxJS\u3002\u6211\u5C06\u628A\u4EE5\u4E0B\u5404\u8282\u4E13\u95E8\u7528\u4E8E\u6BCF\u4E2A\u90E8\u5206\u53CA\u5176\u5404\u81EA\u7684\u7279\u70B9\u3002</p><p>callback \u5728JavaScript\u4E2D\uFF0C\u51FD\u6570\u662F\u7B2C\u4E00\u7C7B\u5BF9\u8C61\uFF0C\u56DE\u8C03\u53EA\u662F\u4F5C\u4E3A\u53C2\u6570\u4F20\u9012\u7ED9\u53E6\u4E00\u4E2A\u51FD\u6570\u7684\u51FD\u6570\u3002\u4E5F\u79F0\u4E3A\u9AD8\u9636\u51FD\u6570\uFF0C\u53EA\u8981\u5F02\u6B65\u5DE5\u4F5C\u5B8C\u6210\uFF0C\u5C31\u5E94\u8BE5\u8C03\u7528\u56DE\u8C03\u3002</p><pre><code>fs.readFile(&#39;./imaginary.txt&#39;, function(err, result) {
    if (err) {
        return console.error(&#39;Error:&#39;, err);
    }
    return console.log(&#39;Result:&#39;, result);
})
</code></pre><p>\u7531\u4E8E\u56DE\u8C03\u53EA\u662F\u51FD\u6570\uFF0C\u6240\u4EE5\u8FD0\u884CJavaScript\u7684\u6240\u6709\u73AF\u5883\u90FD\u652F\u6301\u5B83\u4EEC\uFF0C\u4ECE\u6211\u4EEC\u7684\u6D4F\u89C8\u5668\u5230\u8FD0\u884CNode.js\u7684\u670D\u52A1\u5668\u3002\u8FD9\u79CD\u6A21\u5F0F\u867D\u7136\u7B80\u5355\u4F46\u529F\u80FD\u5F3A\u5927\uFF0C\u4F46\u5374\u662F\u5F02\u6B65\u7684\u57FA\u7840\u3002\u4F46\u662F\uFF0C\u5B83\u4E5F\u6709\u5176\u7F3A\u70B9\u3002</p><p>\u5F53\u9879\u76EE\u5F00\u59CB\u589E\u957F\u5E76\u4E14\u6211\u4EEC\u9700\u8981\u5F00\u59CB\u6267\u884C\u66F4\u590D\u6742\u7684\u4EE3\u7801\u65F6\uFF0C\u5728\u6211\u4EEC\u7684\u7A0B\u5E8F\u4E0A\u5B9E\u73B0\u901A\u7528\u89E3\u51B3\u65B9\u6848\u53D8\u5F97\u66F4\u52A0\u56F0\u96BE\uFF0C\u4F7F\u5F97\u5B83\u4EEC\u66F4\u96BE\u4EE5\u9605\u8BFB\u548C\u7EF4\u62A4\u3002\u5F53\u53D1\u751F\u8FD9\u79CD\u60C5\u51B5\u65F6\uFF0C\u6211\u4EEC\u5F00\u59CB\u5177\u6709})\u7C7B\u4F3C\u4E8E\u4EE5\u4E0B\u793A\u4F8B\u4E2D\u6240\u89C1\u7684\u91D1\u5B57\u5854\u5F62\u72B6\u3002</p><pre><code>fs.readFile(&#39;./imaginary.txt&#39;, function(err, imaginaryResult) {
    if (err) {
        return console.error(&#39;Error:&#39;, err);
    }
    fs.readFile(&#39;./cloud.txt&#39;, function(err, cloudResult) {
        if (err) {
            return console.error(&#39;Error:&#39;, err);
        }
        var res = imaginaryResult + cloudResult;
        fs.writeFile(&#39;./imaginarycloud.txt&#39;, res, function(err) {
            if (error) {
                return console.log(&#39;Error:&#39;, err);
            }
            return console.log(&#39;Success!&#39;);
        })
    })
})
</code></pre><p>\u8FD9\u901A\u5E38\u88AB\u79F0\u4E3A\u201CCallback Hell\u201D\u3002</p><p>\u7136\u800C\uFF0C\u56DE\u8C03\u6700\u7CDF\u7CD5\u7684\u662F\u63A7\u5236\u53CD\u8F6C\u3002\u5982\u679C\u53D1\u751F\u8FD9\u79CD\u60C5\u51B5\uFF0C\u6211\u4EEC\u5C06\u7A0B\u5E8F\u6D41\u7A0B\u5E8F\u5217\u7684\u63A7\u5236\u6743\u4EA4\u7ED9\u5176\u4ED6\u65B9\uFF0C\u4F7F\u5F97\u5BF9\u5176\u8FDB\u884C\u9002\u5F53\u6D4B\u8BD5\u53D8\u5F97\u56F0\u96BE\uFF08\u751A\u81F3\u4E0D\u53EF\u80FD\uFF01\uFF09\u3002</p><p>promise \u627F\u8BFA\u66F4\u96BE\u638C\u63E1\uFF0C\u4F46\u89E3\u51B3\u63A7\u5236\u95EE\u9898\u7684\u5012\u7F6E\u3002\u5B83\u4EEC\u6BD4\u56DE\u8C03\u6162\u4E00\u70B9\uFF0C\u4F46\u4F5C\u4E3A\u56DE\u62A5\uFF0C\u6211\u4EEC\u83B7\u5F97\u4E86\u5F88\u591A\u53EF\u4FE1\u5EA6\u3002</p><p>\u6211\u4EEC\u603B\u662F\u53EF\u4EE5\u786E\u5B9APromise\u4F1A\u89E3\u51B3\u6216\u62D2\u7EDD\uFF0C\u56E0\u4E3A\u5B83\u4EEC\u662F\u56F4\u7ED5\u53EF\u80FD\u5C1A\u4E0D\u5B58\u5728\u7684\u503C\u7684\u201C\u5305\u88C5\u5668\u201D\u3002Promise\u662F\u4E00\u79CD\u53EF\u4FE1\u8D56\u7684\u673A\u5236\uFF0C\u5B83\u4E5F\u6709\u52A9\u4E8E\u4EE5\u66F4\u987A\u5E8F\u7684\u65B9\u5F0F\u8868\u793A\u5F02\u6B65\u4EE3\u7801\u3002\u5B83\u4EEC\u6700\u591A\u53EA\u80FD\u6709\u4E00\u4E2A\u5206\u8FA8\u7387\u503C\uFF0C\u8FD9\u610F\u5473\u7740Promise\u603B\u662F\u9700\u8981\u88AB\u89E3\u51B3\u6216\u62D2\u7EDD\u3002</p><p>\u8FD9\u5C31\u662F\u4ED6\u4EEC\u5982\u4F55\u89E3\u51B3\u63A7\u5236\u53CD\u8F6C\u7684\u95EE\u9898\u3002\u4E0D\u662F\u901A\u8FC7\u5220\u9664\u56DE\u8C03\uFF0C\u800C\u662F\u901A\u8FC7\u5728\u5904\u7406\u6B64\u95EE\u9898\u7684\u5305\u88C5\u5668\u4E0A\u521B\u5EFA\u673A\u5236\u3002</p><p>Promise\u63D0\u4F9B\u66F4\u591A\u529F\u80FD\uFF0C\u4F8B\u5982Promise.all\uFF08\uFF09\u6216Promise.race\uFF08\uFF09\u3002\u901A\u8FC7\u8FD9\u79CD\u64CD\u4F5C\uFF0C\u6211\u4EEC\u53EF\u4EE5\u542F\u52A8\u591A\u4E2A\u5F02\u6B65\u8BF7\u6C42\uFF0C\u5E76\u4E14\u53EA\u6709\u5728\u6240\u6709\u8FD9\u4E9B\u8BF7\u6C42\u90FD\u88AB\u89E3\u6790\u6216\u7B2C\u4E00\u6B21\u5B8C\u6210\u65F6\u624D\u7EE7\u7EED\u3002\u6B64\u5916\uFF0C\u6211\u4EEC\u53EF\u4EE5\u5728\u4EE3\u7801\u4E0A\u94FE\u63A5\u591A\u4E2APromise\uFF0C\u800C\u4E0D\u4F1A\u5728\u6BCF\u4E2A\u4EE3\u7801\u4E4B\u540E\u5F3A\u5236\u4F7F\u7528\u65B0\u7684\u7F29\u8FDB\u7EA7\u522B.then()\u3002</p><pre><code>var promise = new Promise(function(resolve, reject) {
    fs.readFile(&#39;./imaginarycloud.txt&#39;, function(err, result) {
        if (err) {
            return reject(err);
        }
        return resolve(result);
    });
})

promise.then(function(text) {
    console.log(text);
}).catch(function(err) {
    console.error(&#39;Error:&#39;, err);
});
</code></pre><p>\u8FD9\u63D0\u9AD8\u4E86\u4EE3\u7801\u7684\u53EF\u8BFB\u6027\uFF0C\u4EE5\u53CA\u7A0B\u5E8F\u7684\u53EF\u7EF4\u62A4\u6027\uFF0C\u4F46\u5E76\u975E\u4E00\u5207\u90FD\u662F\u5B8C\u7F8E\u7684\u3002\u7531\u4E8E\u6B64\u529F\u80FD\u5904\u4E8E\u6846\u67B6\u7EA7\u522B\uFF0C\u56E0\u6B64\u6709\u591A\u4E2A\u5B9E\u73B0\u53EF\u80FD\u4F1A\u56E0\u884C\u4E3A\u800C\u5F02\uFF0C\u52A0\u4E0A\u65F6\u95F4\u548C\u5185\u5B58\u7684\u5F00\u9500\u6210\u672C\u3002</p><p>generate ECMAScript 2015\u4E0A\u5F15\u5165\u4E86\u751F\u6210\u5668\uFF0C\u5B83\u4EEC\u662F\u6211\u4EEC\u53EF\u4EE5\u4F7F\u7528\u548C\u63A7\u5236\u8FED\u4EE3\u5668\u7684\u51FD\u6570\uFF0C\u8FD9\u610F\u5473\u7740\u51FD\u6570\u53EF\u4EE5\u968F\u65F6\u6682\u505C\u548C\u6062\u590D\u3002\u8FD9\u662F\u4E00\u4E2A\u5F3A\u5927\u7684\u5DE5\u5177\uFF0C\u5F53\u6211\u4EEC\u60F3\u8981\u4EC5\u5728\u9700\u8981\u65F6\u83B7\u53D6\u6BCF\u4E2A\u503C\u65F6\uFF0C\u800C\u4E0D\u662F\u4E00\u6B21\u6027\u83B7\u53D6\u6240\u6709\u503C\u3002\u8FD9\u53EF\u4EE5\u901A\u8FC7\u5728JavaScript\u4E2D\u6DFB\u52A0\u201Cyield\u201D\u4E00\u8BCD\u6765\u5B9E\u73B0\u3002</p><pre><code>function* iterate(array) {
    for(var value of array) {
        yield value
    }
}

var it = iterate([&#39;Imaginary&#39;, &#39;Cloud&#39;]);
it.next();
it.next();
it.next();

// RESULT:
// { value: &#39;Imaginary&#39;, done: false }
// { value: &#39;Cloud&#39;, done: false }
// { value: undefined, done: true }
</code></pre><p>\u6211\u4EEC\u53EF\u4EE5\u5728\u8FD9\u4E2A\u4F8B\u5B50\u4E2D\u770B\u5230\uFF0C\u6BCF\u4E2Anext()\u6211\u4EEC\u90FD\u4F1A\u6536\u5230\u4E00\u4E2A\u5E26\u6709\u503C\u7684\u5BF9\u8C61\u548C\u4E00\u4E2A\u6307\u793A\u751F\u6210\u5668\u51FD\u6570\u662F\u5426\u7ED3\u675F\u7684\u6807\u5FD7\u3002\u4F46\u662F\u751F\u6210\u5668\u4E5F\u53EF\u4EE5\u7528\u6765\u63A7\u5236\u4E0E\u5176\u4ED6\u5E93\u7ED3\u5408\u7684\u5F02\u6B65\u6D41\uFF0C\u6BD4\u5982co\u6216redux-saga\uFF0C\u6211\u5C06\u5728\u540E\u9762\u8FDB\u4E00\u6B65\u8BA8\u8BBA\u3002</p><p>async/await \u6700\u540E\uFF0CES2017\u5F15\u5165\u4E86\u5F02\u6B65\u51FD\u6570\uFF0C\u4F7F\u5F97\u5728JavaScript\u4E2D\u7F16\u5199\u548C\u8BFB\u53D6\u5F02\u6B65\u4EE3\u7801\u53D8\u5F97\u66F4\u52A0\u5BB9\u6613\uFF01</p><p>\u5B83\u4EEC\u6BD4\u6700\u540E\u8BA8\u8BBA\u7684\u6A21\u5F0F\u66F4\u6E05\u6670\uFF0C\u5F02\u6B65\u51FD\u6570\u7684\u8FD4\u56DE\u662F\u4E00\u4E2APromise\uFF01\u8FD9\u975E\u5E38\u5F3A\u5927\uFF0C\u56E0\u4E3A\u6211\u4EEC\u62E5\u6709\u4E24\u4E2A\u4E16\u754C\u7684\u4F18\u70B9\u3002\u6B63\u5982\u6211\u4EEC\u4E4B\u524D\u6240\u8BA8\u8BBA\u7684\uFF0CPromises\u5728\u5904\u7406\u590D\u6742\u7684\u5F02\u6B65\u64CD\u4F5C\u65F6\u662F\u5B89\u5168\u7684\u9009\u62E9\uFF0C\u4F46\u5B83\u4EEC\u5E76\u4E0D\u50CFasync / await\u4EE3\u7801\u90A3\u6837\u5BB9\u6613\u9605\u8BFB\u548C\u638C\u63E1\u3002</p><p>\u4E00\u4E2A\u7F3A\u70B9\u662F\u5B83\u9700\u8981\u4E00\u4E2A\u50CFBabel\u4E00\u6837\u7684\u8F6C\u6362\u5DE5\u5177\uFF0C\u56E0\u4E3AAsync / Await\u4ECD\u7136\u662Fpromises\u4EE3\u7801\u7684\u8BED\u6CD5\u7CD6\u3002</p><p>\u7531\u4E8E\u7ED3\u679C\u662FPromise\u5E76\u4E14\u53EF\u4EE5\u89E3\u6790/\u62D2\u7EDD\uFF0C\u56E0\u6B64\u5C06await\u4EE3\u7801\u5305\u88C5\u5728try / catch\u4E2D\u975E\u5E38\u91CD\u8981\u3002\u8FD9\u6837\u6211\u4EEC\u5C31\u80FD\u591F\u6B63\u786E\u5904\u7406\u5F02\u6B65\u4EE3\u7801\u7684\u9519\u8BEF\u3002</p><pre><code>async function() {
    try {
        var result = await fetch(&#39;https://imaginaryAPI&#39;);
        return result
    } catch (err) {
        return console.error(&#39;Error:&#39;, err);
    }
}
</code></pre><p>web worker \u4F7F\u7528Web-worker\uFF0C\u53EF\u4EE5\u5728\u4E0D\u540C\u7684\u7EBF\u7A0B\u4E0A\u8FD0\u884C\u811A\u672C\u548C\u51FD\u6570\u3002\u8FD9\u4E0D\u4F1A\u5F71\u54CD\u7528\u6237\u754C\u9762\u7684\u53EF\u7528\u6027\uFF0C\u5E76\u4E14\u53EF\u4EE5\u5728\u5DE5\u4F5C\u4EBA\u5458\u548C\u4E3B\u7EBF\u7A0B\u4E4B\u95F4\u53D1\u9001\u6570\u636E\u3002</p><p>\u6D4F\u89C8\u5668\u4E0A\u7684\u670D\u52A1\u5DE5\u4F5C\u8005\u5927\u91CF\u7528\u4E8E\u6E10\u8FDB\u5F0FWeb\u5E94\u7528\u7A0B\u5E8F\u3002\u8FD9\u5305\u62EC\u4E3A\u6211\u4EEC\u7684\u7F51\u7AD9\u6CE8\u518CWeb\u5DE5\u4F5C\u8005\u5E76\u51B3\u5B9A\u54EA\u4E9B\u6587\u4EF6\u53EF\u4EE5\u7F13\u5B58\uFF0C\u8FD9\u5C06\u4F7F\u5E94\u7528\u7A0B\u5E8F\u7684\u4F7F\u7528\u66F4\u5FEB\u3002\u6B64\u5916\uFF0C\u5982\u679C\u7528\u6237\u5904\u4E8E\u79BB\u7EBF\u72B6\u6001\uFF0C\u5219\u67D0\u4E9B\u529F\u80FD\u4ECD\u53EF\u7528\u3002\u5B83\u4EEC\u8FD8\u53EF\u7528\u4E8E\u6267\u884C\u7E41\u91CD\u7684\u64CD\u4F5C\uFF0C\u800C\u4E0D\u4F1A\u51BB\u7ED3UI\u6216\u4E3BJS\u7EBF\u7A0B\u3002</p><p>NPM libary \u8FD8\u6709\u5176\u4ED6\u51E0\u4E2A\u5E93\u8BD5\u56FE\u89E3\u51B3\u8FD9\u4E9B\u95EE\u9898\uFF0C\u6BCF\u4E2A\u5E93\u90FD\u4F7F\u7528\u81EA\u5DF1\u7684\u6280\u672F\u3002\u4F60\u53EF\u4EE5\u5728\u524D\u9762\u627E\u5230\u4E00\u4E9B\u4F8B\u5B50\uFF1A</p><p>\u5F02\u6B65\uFF1A\u8FD9\u4E2A\u5E93\u5F88\u9002\u5408\u5904\u7406\u56DE\u8C03\u8BD5\u56FE\u89E3\u51B3\u5176\u4E2D\u5B58\u5728\u7684\u4E00\u4E9B\u95EE\u9898\uFF0C\u4EE5\u53CA\u6D88\u9664\u56DE\u8C03\u5730\u72F1\u95EE\u9898\uFF01\u5728\u6700\u540E\u7684\u5B9E\u73B0\u4E2D\uFF0C\u4E5F\u53EF\u4EE5\u4F7F\u7528Async / await\u4EE3\u7801\u3002</p><pre><code>async.waterfall([
    function(callback),
    function(callback),
], function(err) {
    console.error(&#39;Error:&#39;, err);
});
</code></pre><p>Bluebird\uFF1A\u4E00\u4E2A\u975E\u5E38\u9AD8\u6027\u80FD\u7684Promises\u5B9E\u73B0\uFF0C\u8FD8\u5305\u62EC\u5F88\u591A\u989D\u5916\u7684\u529F\u80FD\uFF0C\u5982\u53D6\u6D88\uFF0C\u8FED\u4EE3\u548CPromisify\uFF01\u6700\u540E\u4E00\u4E2A\u662F\u4F7F\u7528\u56DE\u8C03\u7684\u51FD\u6570\u7684\u5305\u88C5\u5668\uFF0C\u4E3A\u8FD9\u4E9B\u51FD\u6570\u8FD4\u56DE\u4E00\u4E2APromise\u3002</p><pre><code>var module = require(&#39;imaginary-callback-module&#39;);
Promise.promisifyAll(module)

// RESULT:
// Now we can call .then() on all module functions, yeaaah!
</code></pre><p>co\uFF1A\u7528\u751F\u6210\u5668\u63A7\u5236\u5F02\u6B65\u6D41\u3002\u8FD9\u4E2A\u5E93\u662F\u4E00\u4E2A\u56F4\u7ED5\u751F\u6210\u5668\u7684\u8FD0\u884C\u65F6\uFF0C\u5B83\u5C06\u5173\u952E\u5B57yield\u4E0Epromises\u76F8\u7ED3\u5408\uFF0C\u6267\u884C\u751F\u6210\u5668\u7ED3\u679C\u5E76\u5C06\u5176\u4F5C\u4E3Apromise\u5BF9\u8C61\u8FD4\u56DE\u3002</p><pre><code>co(function* () {
    var auth = yield login(username, password);
    return auth;
}).then(function(result) {
    console.log(result);
}, function(err) {
    console.error(err);
});
</code></pre><p>Redux-saga\uFF1AReact / Redux\u5806\u6808\u7684\u524D\u7AEF\u5E93\u3002\u8FD9\u662F\u4E00\u4E2ARedux\u4E2D\u95F4\u4EF6\uFF0C\u65E8\u5728\u4F7F\u5E94\u7528\u7A0B\u5E8F\u526F\u4F5C\u7528\u66F4\u9AD8\u6548\uFF0C\u66F4\u6613\u4E8E\u7BA1\u7406\uFF0C\u56E0\u4E3A\u5B83\u4EEC\u53EF\u4EE5\u901A\u8FC7Redux\u64CD\u4F5C\u542F\u52A8\u6216\u53D6\u6D88\u3002\u6B64\u5B9E\u73B0\u5927\u91CF\u4F7F\u7528\u751F\u6210\u5668\u6765\u901A\u8FC7Internet\u83B7\u53D6\u6570\u636E\u5E76\u5728\u6211\u4EEC\u7684\u7F51\u7AD9\u4E0A\u5E94\u7528\u6240\u9700\u7684\u526F\u4F5C\u7528\u3002</p><pre><code>function* (username, password) {
    try {
        var auth = yield call(login, username, password);
        yield put(someActionToStore(auth));
    } catch (err) {
        console.error(&#39;Error:&#39;, err);
    }
}
</code></pre><p>RxJS\uFF1A\u8FD9\u662FAngular\u5E94\u7528\u7A0B\u5E8F\u4F7F\u7528\u7684\u6A21\u5F0F\uFF0C\u5B83\u662F\u4E00\u79CD\u53CD\u5E94\u6A21\u5F0F\u3002\u57FA\u672C\u4E0A\uFF0C\u6211\u4EEC\u521B\u5EFA\u4E00\u4E2A\u53EF\u89C2\u5BDF\u5BF9\u8C61\uFF0C\u5E76\u8BA2\u9605\u6211\u4EEC\u5C06\u6536\u5230\u901A\u77E5\u7684\u66F4\u6539\u3002\u4F8B\u5982\uFF0C\u4F7F\u7528\u6B64\u6A21\u5F0F\uFF0C\u53EF\u4EE5\u53D6\u6D88\u8BA2\u9605\u548C\u94FE\u53EF\u89C2\u5BDF\u5BF9\u8C61\u3002</p><pre><code>Observable.first().subscribe(function(result) {
    console.log(&#39;Result:&#39;, result);
}, function(error) {
    console.error(&#39;Error:&#39;, error);
})
</code></pre><p>\u7ED3\u8BBA \u5BF9\u4E8E\u7B80\u5355\u9879\u76EE\uFF0C\u56DE\u8C03\u662F\u5904\u7406\u5F02\u6B65\u6D41\u7684\u6700\u7B80\u5355\uFF0C\u6700\u7B80\u5355\u7684\u65B9\u6CD5\u3002\u5728\u5177\u6709\u9002\u5F53\u8BBE\u7F6E\u7684\u8F83\u5927\u9879\u76EE\u4E2D\uFF0C\u6211\u4F1A\u9009\u62E9\u5F02\u6B65/\u7B49\u5F85\u6A21\u5F0F\uFF0C\u56E0\u4E3A\u5F02\u6B65\u6027\u6613\u4E8E\u9605\u8BFB\uFF0C\u5177\u6709\u81EA\u7136\u7684\u9519\u8BEF\u5904\u7406\u5E76\u4E14\u6CA1\u6709\u6B7B\u4EA1\u7684\u91D1\u5B57\u5854\u3002</p><p>\u8FD9\u662F\u6211\u4EEC\u5DE5\u4F5C\u4E2D\u9700\u8981\u7684\u4E00\u79CD\u8BED\u6CD5\u7CD6\uFF0C\u5141\u8BB8\u6211\u4EEC\u7F16\u5199\u4E00\u4E2A\u66F4\u6613\u8BFB\u548C\u53EF\u7EF4\u62A4\u7684\u7A0B\u5E8F\u3002</p><p>JavaScript\u7EE7\u7EED\u6210\u4E3Agithub\u4E0A\u6700\u5E38\u7528\u7684\u8BED\u8A00\uFF0C\u4EE5\u53CA\u5176\u5145\u6EE1\u6D3B\u529B\u7684\u793E\u533A\u3002\u8FD9\u662F\u6211\u4EEC\u5904\u7406\u5F02\u6B65\u6D41\u7A0B\u7684\u9996\u9009\uFF0C\u4F46\u9664\u4E86\u672C\u6307\u5357\u6240\u63CF\u8FF0\u7684\u7ED3\u679C\u4E4B\u5916\uFF0C\u8FD8\u6709\u66F4\u591A\u65B9\u6CD5\u53EF\u4EE5\u5B9E\u73B0\u76F8\u540C\u7684\u7ED3\u679C\u3002\u603B\u800C\u8A00\u4E4B\uFF0C\u60A8\u53EF\u4EE5\u81EA\u884C\u9009\u62E9\u6700\u9002\u5408\u60A8\u9700\u6C42\u7684\u4EA7\u54C1\u3002</p>`,40);function g(v,_){const n=t("ExternalLinkIcon");return a(),c(i,null,[u,e("blockquote",null,[e("p",null,[d,e("a",m,[f,s(n)]),y])]),h],64)}var x=o(p,[["render",g],["__file","async.html.vue"]]);export{x as default};
